  5→import { getNotifications } from "../../../API/Api";
  6→import { useEffect, useRef, useState, useMemo } from "react";
  7→import FormatNotificationType from "../../../helpers/formatNoficationType";
  8→import formatPostDate from "../../../helpers/formatDateString";
  9→import { handleCLickContent, handleClickOpinion } from "../../../helpers/handleClicks";
 10→import { useNavigate } from "react-router-dom";
