 14→import { handleImageFallback } from "../../utils/handleImageFallback";
 15→import { getReactionEmoji } from "../../utils/reactionConfig";
 16→
 17→const NOTIFICATION_ICON_ARRAY = [
 18→    {
 19→        type: 'like',
 20→        icon:
 21→        <svg className="svg-like" xmlns="http://www.w3.org/2000/svg" width="30px" height="30px" viewBox="0 0 24 24" fill="none">
