 98→const NotificationCards = () =>{
 99→    const {user, session} = useAuth();
100→    const {ref, inView} = useInView({
101→        threshold: 0.2
102→    })
103→    const navigate = useNavigate();
104→
105→    const scrollToTop = useRef();
106→    const modalRef = useRef();
107→    const [settingsId, setSettingsId] = useState(null);
108→
109→    const iconArray = NOTIFICATION_ICON_ARRAY;
110→
111→    const handleClickNotif = handleCLickContent(navigate);
112→    const handleClickOpinionNotif = handleClickOpinion(navigate);
113→    const mutationReadNotif = useReadNotificationMutation(session);
114→
115→    const handleReadNotif = async(e, notification) => {
116→        e.stopPropagation();
117→        const source = notification?.source || 'journal';
118→        mutationReadNotif.mutate({notifId: notification.id, source})
119→
120→        if(source === 'opinion'){
121→            handleClickOpinionNotif(e, notification?.opinions?.id, notification?.opinions?.user_id)
122→        } else if(notification?.type === 'follow'){
123→            navigate(`/visitProfile?userId=${notification?.sender_id}`);
124→        } else if(notification?.type === 'repost' && notification?.repost_journal_id){
125→            // Navigate to the repost post (quote + embedded original)
126→            const repostId = notification.repost_journal_id;
127→            const encodedId = encodeURIComponent(repostId);
128→            navigate(`/home/post/${encodedId}`);
129→        } else {
130→            handleClickNotif(
131→                e,
132→                null,
133→                '',
134→                notification?.journals?.title,
135→                notification?.journals?.users.id,
136→                notification?.journals?.users?.name,
137→                notification?.journals?.users?.image_url,
138→                notification?.journals?.created_at,
139→                notification?.journal_id,
140→                notification?.hasLiked,
141→                0,
142→                notification?.hasBookMarked,
143→                0,
144→                0,
145→                notification?.journals?.users?.badge,
146→            )
147→        }
148→    }
149→
150→    const {data, isLoading, hasNextPage, isFetchingNextPage, fetchNextPage} = useInfiniteQuery({
151→        queryKey: ['getNotifications', session?.user?.id],
152→        queryFn: ({pageParam = null}) => getNotifications(session?.access_token, pageParam, 5),
153→        getNextPageParam: (lastpage) =>{
154→            if(lastpage?.hasMore){
155→                const lastNotification = lastpage?.data[lastpage?.data.length - 1];
156→                return new Date(lastNotification.created_at).toISOString();
157→
158→            }
159→            return undefined;
160→        },
161→        enabled: !!session?.access_token,
162→        refetchOnWindowFocus: false,
163→        staleTime: 1000 * 60 * 2
164→    })
165→
166→    useEffect(() =>{
167→        if(scrollToTop.current && !isLoading){
168→            scrollToTop.current.scrollIntoView({behavior: 'smooth'});
169→        }
170→    }, [isLoading])
171→
172→    useEffect(() =>{
173→        if(hasNextPage && !isFetchingNextPage && inView){
174→            // console.log(hasNextPage)
175→            fetchNextPage();
176→        }
177→    }, [hasNextPage, isFetchingNextPage, inView, fetchNextPage])
178→
179→    const notifications = useMemo(() => data?.pages?.flatMap((page) => page?.data) || [], [data]);
180→
181→    useEffect(() =>{
182→        const handleClickOutside = (e) =>{
183→            if(modalRef.current && !modalRef.current.contains(e.target)){
184→                setSettingsId(null);
185→                // console.log('close')
186→            }
187→        }
188→
189→        document.addEventListener('click', handleClickOutside);
190→        return () =>{
191→            document.removeEventListener('click', handleClickOutside)
192→        }
193→    }, [])
194→
195→     useEffect(() =>{
196→         // console.log(data)
197→    }, [data])
198→
199→    const handleClickSettings = (e, notifId) =>{
200→        e.stopPropagation();
201→        // console.log(notifId)
202→        setSettingsId(settingsId === notifId ? null : notifId);
203→    }
204→
205→    const mutationDeleteNotif  = useUserDeleteNotificationMutation(session);
206→
207→    const handleClickDeleteNotification = async(e, notifId, source) =>{
208→        e.stopPropagation();
209→        try {
210→           const message = mutationDeleteNotif.mutateAsync({notifId, source});
211→            if(message){
212→                // console.log(message)
213→            }
214→        } catch (error) {
215→            console.error('error while deleting notification:', error)
216→        }
217→    }
218→
219→    if(notifications.length === 0 && !isLoading){
220→        return(
221→            <div className='notification-loading-container'>
222→                No notifications availabe
223→            </div>
224→        )
225→    }
226→
227→    if(isLoading){
228→        return(
229→            <div className="notification-loading-container">
