239→            {notifications?.map((notification) => {
240→                const isOpinion = notification?.source === 'opinion';
241→                const displayType = isOpinion
242→                    ? (notification?.type === 'mention' ? 'mention' : 'opinion_reply')
243→                    : notification?.type;
244→                const previewText = !isOpinion ? (notification?.journals?.preview_text || '') : '';
245→                const thumbnailUrl = !isOpinion ? (notification?.journals?.thumbnail_url || null) : null;
246→
247→                return(
248→                <div key={`${notification.source}-${notification.id}`} className={notification?.read ? "notification-cards" : "notification-cards-unread"}>
249→
250→                    <div className="notification-cards-child-container">
