258→                                iconArray.map((icon, index) => (
259→                                    <div className="notification-icon" key={index}>
260→                                        {icon.type === displayType ? icon.icon : null}
261→                                    </div>
262→                                ))
263→                            )}
264→                        </div>
265→
266→                        <div className="notification-contents-container">
267→
268→                            <div className="notification-sender-user-metadata">
269→                                <div className="notification-sender-user-metadata-child">
